     7	use anyhow::{Context, Result};
     8	use futures::StreamExt;
     9	use serde_json::Value;
    10	
    11	use crate::provider::{CompletionRequest, StreamChunk};
    12	
    13	use super::OpenAIProvider;
    14	use super::sse_drive::drive;
    15	
    16	impl OpenAIProvider {
    17	    /// True for providers whose models stream vendor `reasoning_content`.
    18	    pub(super) fn uses_reasoning_stream(&self) -> bool {
    19	        self.provider_name == "cerebras"
    20	    }
    21	
    22	    /// Stream a completion via raw SSE, capturing reasoning content.
    23	    pub(super) async fn reasoning_stream(
    24	        &self,
    25	        request: CompletionRequest,
    26	        body: Value,
    27	    ) -> Result<futures::stream::BoxStream<'static, StreamChunk>> {
    28	        let url = format!("{}/chat/completions", self.api_base.trim_end_matches('/'));
    29	        let mut req = self.http.post(url).json(&body);
    30	        if let Some(key) = self.api_key.as_deref().filter(|k| !k.is_empty()) {
    31	            req = req.bearer_auth(key);
    32	        }
    33	        let response = req.send().await.context("send reasoning stream request")?;
    34	        let status = response.status();
    35	        if !status.is_success() {
    36	            let text = response.text().await.unwrap_or_default();
    37	            let msg = format!("{} stream error ({status}): {}", request.model, text);
    38	            return Ok(futures::stream::iter(vec![
    39	                StreamChunk::Error(msg),
    40	                StreamChunk::Done { usage: None },
    41	            ])
    42	            .boxed());
    43	        }
    44	        Ok(drive(response.bytes_stream()).boxed())
