     2	
     3	use crate::provider::StreamChunk;
     4	
     5	use super::sse_lines::drain_lines;
     6	
     7	/// Drive a byte stream into ordered [`StreamChunk`]s.
     8	pub(super) fn drive(
     9	    bytes: impl futures::Stream<Item = reqwest::Result<bytes::Bytes>> + Send + 'static,
    10	) -> impl futures::Stream<Item = StreamChunk> + Send + 'static {
    11	    use futures::StreamExt;
    12	    let mut buffer = String::new();
    13	    let mut produced = false;
    14	    let mut usage = None;
    15	    bytes.flat_map(move |result| {
    16	        let mut out = Vec::new();
    17	        match result {
    18	            Ok(b) => {
    19	                buffer.push_str(&String::from_utf8_lossy(&b));
    20	                drain_lines(&mut buffer, &mut produced, &mut usage, &mut out);
    21	            }
    22	            Err(e) => out.push(StreamChunk::Error(e.to_string())),
    23	        }
    24	        futures::stream::iter(out)
    25	    })
    26	}
