    11	        prompt_tokens: u.prompt_tokens,
    12	        completion_tokens: u.completion_tokens,
    13	        total_tokens: u.total_tokens,
    14	        cache_read_tokens: None,
    15	        cache_write_tokens: None,
    16	    }
