    19	/// Map a full SSE frame to chunks, recording whether output was produced.
    20	pub(super) fn frame_chunks(parsed: &SseResponse, produced: &mut bool) -> Vec<StreamChunk> {
    21	    let mut out = Vec::new();
    22	    let Some(choice) = parsed.choices.first() else {
    23	        return out;
    24	    };
    25	    if let Some(r) = &choice.delta.reasoning_content
    26	        && !r.is_empty()
    27	    {
    28	        *produced = true;
    29	        out.push(StreamChunk::Thinking(r.clone()));
    30	    }
    31	    if let Some(c) = &choice.delta.content
    32	        && !c.is_empty()
    33	    {
    34	        *produced = true;
    35	        out.push(StreamChunk::Text(c.clone()));
    36	    }
    37	    if let Some(tcs) = &choice.delta.tool_calls {
    38	        for tc in tcs {
    39	            let chunks = tool_chunks(tc);
    40	            if !chunks.is_empty() {
    41	                *produced = true;
    42	            }
    43	            out.extend(chunks);
    44	        }
    45	    }
    46	    out
    47	}
