     8	/// Consume complete lines from `buffer`, appending chunks to `out`.
     9	pub(super) fn drain_lines(
    10	    buffer: &mut String,
    11	    produced: &mut bool,
    12	    usage: &mut Option<Usage>,
    13	    out: &mut Vec<StreamChunk>,
    14	) {
    15	    while let Some(end) = buffer.find('\n') {
    16	        let line = buffer[..end].trim().to_string();
    17	        *buffer = buffer[end + 1..].to_string();
    18	        if line == "data: [DONE]" {
    19	            if !*produced {
    20	                out.push(StreamChunk::Error(
    21	                    "stream ended without producing any content (empty response)".to_string(),
    22	                ));
    23	            }
    24	            out.push(StreamChunk::Done {
    25	                usage: usage.take(),
    26	            });
    27	            continue;
    28	        }
    29	        let Some(data) = line.strip_prefix("data: ") else {
    30	            continue;
    31	        };
    32	        let Ok(parsed) = serde_json::from_str::<SseResponse>(data) else {
    33	            continue;
    34	        };
    35	        if let Some(u) = &parsed.usage {
    36	            *usage = Some(to_usage(u));
    37	        }
    38	        out.extend(frame_chunks(&parsed, produced));
    39	    }
    40	}
