     1	//! Repair malformed tool-call/result sequences before sending upstream.
     2	//!
     3	//! OpenAI-compatible APIs (Cerebras included) reject a request where an
     4	//! assistant message carrying `tool_calls` is not immediately answered by a
     5	//! `tool` message for every `tool_call_id`. This happens when a user presses
     6	//! "continue" while a tool call is still pending, inserting a user turn right
     7	//! after a dangling tool call. Such a request faults with a 400 and surfaces
     8	//! as `stream faulted (transient=false)`. We splice in synthetic tool results
     9	//! so the conversation stays well-formed.
    10	
    11	use serde_json::{Value, json};
    12	
    13	const INTERRUPTED: &str = "[no result: tool call was interrupted]";
    14	
    15	/// Insert synthetic `tool` messages for any unanswered assistant tool calls.
    16	pub(super) fn repair_tool_results(messages: Vec<Value>) -> Vec<Value> {
    17	    let mut out: Vec<Value> = Vec::with_capacity(messages.len());
    18	    for (idx, msg) in messages.iter().enumerate() {
    19	        let ids = pending_tool_ids(msg);
    20	        out.push(msg.clone());
    21	        if ids.is_empty() {
    22	            continue;
    23	        }
    24	        let answered = answered_ids(&messages, idx + 1, &ids);
    25	        for id in ids.iter().filter(|id| !answered.contains(*id)) {
    26	            out.push(json!({
    27	                "role": "tool",
    28	                "tool_call_id": id,
    29	                "content": INTERRUPTED,
    30	            }));
    31	        }
    32	    }
    33	    out
    34	}
    35	
    36	/// Collect tool-call ids declared by an assistant message.
    37	fn pending_tool_ids(msg: &Value) -> Vec<String> {
    38	    if msg.get("role").and_then(Value::as_str) != Some("assistant") {
    39	        return Vec::new();
    40	    }
    41	    msg.get("tool_calls")
    42	        .and_then(Value::as_array)
    43	        .map(|calls| {
    44	            calls
    45	                .iter()
    46	                .filter_map(|c| c.get("id").and_then(Value::as_str))
    47	                .map(str::to_string)
    48	                .collect()
    49	        })
    50	        .unwrap_or_default()
    51	}
    52	
    53	/// Ids answered by consecutive `tool` messages starting at `from`.
    54	fn answered_ids(messages: &[Value], from: usize, ids: &[String]) -> Vec<String> {
    55	    let mut found = Vec::new();
    56	    for msg in &messages[from..] {
    57	        if msg.get("role").and_then(Value::as_str) != Some("tool") {
    58	            break;
    59	        }
    60	        if let Some(id) = msg.get("tool_call_id").and_then(Value::as_str)
    61	            && ids.iter().any(|want| want == id)
    62	        {
    63	            found.push(id.to_string());
    64	        }
    65	    }
    66	    found
    67	}
