     1	//! [`Stream`] implementation for [`SseChunkStream`].
     2	//!
     3	//! Separated from the struct definition to keep each file under 50 lines.
     4	//!
     5	//! ## EOF handling
     6	//!
     7	//! Anthropic's SSE wire protocol emits a `message_delta` event carrying
     8	//! `StreamChunk::Done` **before** the HTTP body closes. So a clean stream
     9	//! looks like: … `Done`(from message_delta) … `Ready(None)`.
    10	//!
    11	//! When the HTTP body closes (`Ready(None)`):
    12	//! - If a real `Done` was already seen (`saw_done == true`): yield `None`
    13	//!   to end the stream cleanly with no duplicate chunk.
    14	//! - If no `Done` was seen (`saw_done == false`): the connection dropped
    15	//!   before the model signalled completion. Yield a transient
    16	//!   `StreamChunk::Error` so the SRP drain classifies this as
    17	//!   `StreamStop::Fault { transient: true }` and fires a restart instead
    18	//!   of silently accepting a truncated reply as `StreamStop::Clean`.
    19	
    20	use futures::Stream;
    21	
    22	use super::sse_stream::SseChunkStream;
    23	use crate::provider::StreamChunk;
    24	
    25	impl Stream for SseChunkStream {
    26	    type Item = StreamChunk;
    27	
    28	    fn poll_next(
    29	        mut self: std::pin::Pin<&mut Self>,
    30	        cx: &mut std::task::Context<'_>,
    31	    ) -> std::task::Poll<Option<Self::Item>> {
    32	        loop {
    33	            if let Some(pos) = self.buffer.find('\n') {
    34	                let line = self.buffer[..pos].to_string();
    35	                self.buffer = self.buffer[pos + 1..].to_string();
    36	                if let Some(chunk) = self.process_line(&line) {
    37	                    if matches!(chunk, StreamChunk::Done { .. }) {
    38	                        self.saw_done = true;
    39	                    }
    40	                    return std::task::Poll::Ready(Some(chunk));
    41	                }
    42	                continue;
    43	            }
    44	            match self.inner.as_mut().poll_next(cx) {
    45	                std::task::Poll::Ready(Some(Ok(bytes))) => {
    46	                    self.buffer.push_str(&String::from_utf8_lossy(&bytes));
    47	                    continue;
    48	                }
    49	                std::task::Poll::Ready(Some(Err(e))) => {
    50	                    return std::task::Poll::Ready(Some(StreamChunk::Error(e.to_string())));
    51	                }
    52	                std::task::Poll::Ready(None) if self.saw_done => {
    53	                    // Clean close after a real Done — end the stream normally.
    54	                    return std::task::Poll::Ready(None);
    55	                }
    56	                std::task::Poll::Ready(None) => {
    57	                    // Byte stream closed before any Done: premature EOF.
    58	                    return std::task::Poll::Ready(Some(StreamChunk::Error(
    59	                        "Anthropic stream closed before message_stop (premature EOF)".into(),
    60	                    )));
    61	                }
    62	                std::task::Poll::Pending => return std::task::Poll::Pending,
    63	            }
    64	        }
    65	    }
    66	}
