  10 | 
  11 | /// Retry pre-content transient failures privately with bounded backoff.
  12 | pub(in crate::provider::openai_codex) fn with_http_retry<F, Fut>(
  13 |     primary: Option<Chunks>,
  14 |     mut retry: F,
  15 | ) -> Chunks
  16 | where
  17 |     F: FnMut() -> Fut + Send + 'static,
  18 |     Fut: Future<Output = Result<Chunks>> + Send + 'static,
  19 | {
  20 |     Box::pin(async_stream::stream! {
  21 |         if let Some(primary) = primary {
  22 |             match attempt::inspect(primary).await {
  23 |                 Outcome::Ready(first, mut remaining) => {
  24 |                     yield first;
  25 |                     while let Some(chunk) = remaining.next().await { yield chunk; }
  26 |                     return;
  27 |                 }
  28 |                 Outcome::Retry(reason) => log_retry(0, &reason),
  29 |             }
  30 |         }
  31 |         for number in 1..=MAX_HTTP_ATTEMPTS {
  32 |             let outcome = match retry().await {
  33 |                 Ok(stream) => attempt::inspect(stream).await,
  34 |                 Err(error) if classify::is_retryable(&format!("{error:#}")) => Outcome::Retry(format!("{error:#}")),
  35 |                 Err(error) => Outcome::Ready(StreamChunk::Error(format!("{error:#}")), Box::pin(futures::stream::empty())),
  36 |             };
  37 |             match outcome {
  38 |                 Outcome::Ready(first, mut remaining) => {
  39 |                     yield first;
  40 |                     while let Some(chunk) = remaining.next().await { yield chunk; }
  41 |                     return;
  42 |                 }
  43 |                 Outcome::Retry(reason) if number < MAX_HTTP_ATTEMPTS => {
  44 |                     log_retry(number, &reason);
  45 |                     tokio::time::sleep(Duration::from_secs(1 << (number - 1))).await;
  46 |                 }
  47 |                 Outcome::Retry(reason) => {
  48 |                     yield StreamChunk::Error(format!("temporary Codex transport failure after {number} attempts: {reason}"));
  49 |                 }
  50 |             }
  51 |         }
  52 |     })
  53 | }
