  10 | 
  11 | /// Buffer one WebSocket attempt until completion so interrupted output stays private.
  12 | pub(super) fn drive<S>(
  13 |     mut connection: OpenAiRealtimeConnection<S>,
  14 |     body: Value,
  15 |     health: TransportHealth,
  16 | ) -> BoxStream<'static, StreamChunk>
  17 | where
  18 |     S: AsyncRead + AsyncWrite + Unpin + Send + 'static,
  19 | {
  20 |     Box::pin(async_stream::stream! {
  21 |         if let Err(error) = connection.send_event(&body).await {
  22 |             interrupted(&health, Some(&error));
  23 |             let _ = connection.close().await;
  24 |             return;
  25 |         }
  26 |         let mut parser = ResponsesSseParser::default();
  27 |         let mut buffered = Vec::new();
  28 |         loop {
  29 |             match connection.recv_event().await {
  30 |                 Ok(Some(event)) => {
  31 |                     OpenAiCodexProvider::parse_responses_event(&mut parser, &event, &mut buffered);
  32 |                     if buffered.iter().any(|chunk| matches!(chunk, StreamChunk::Error(_))) {
  33 |                         let error = buffered.pop().expect("error chunk exists");
  34 |                         yield error;
  35 |                         break;
  36 |                     }
  37 |                     if buffered.iter().any(|chunk| matches!(chunk, StreamChunk::Done { .. })) {
  38 |                         for chunk in buffered.drain(..) { yield chunk; }
  39 |                         break;
  40 |                     }
  41 |                 }
  42 |                 Ok(None) => { interrupted(&health, None); break; }
  43 |                 Err(error) => { interrupted(&health, Some(&error)); break; }
  44 |             }
  45 |         }
  46 |         let _ = connection.close().await;
  47 |     })
  48 | }
