   1 | //! Step-limit outcome tracking for non-interactive resumable runs.
   2 | //!
   3 | //! Uses a thread-local flag so that concurrent sessions in separate threads
   4 | //! (swarm, relay, server) do not race on a single global. Each CLI invocation
   5 | //! or task-fiber gets its own independent flag.
   6 | //!
   7 | //! # Semantics
   8 | //!
   9 | //! The flag starts **cleared** (`false`). When a step-limited run begins,
  10 | //! [`mark_budget_active`] sets it to `true`. At the end of the agentic loop:
  11 | //! - [`clear_budget`] is called if the run completed normally (did not hit
  12 | //!   the step limit), setting the flag back to `false`.
  13 | //! - If the flag is still `true` when the loop exits, the step budget was
  14 | //!   exhausted without calling [`clear_budget`].
  15 | //!
  16 | //! [`was_budget_exhausted`] returns `true` only when the budget was active
  17 | //! and was not cleared, meaning the loop hit the step ceiling.
  18 | 
  19 | use std::cell::Cell;
  20 | 
  21 | thread_local! {
  22 |     static BUDGET_ACTIVE: Cell<bool> = const { Cell::new(false) };
  23 | }
  24 | 
  25 | /// Mark a step-limited run as active. Call at the start of the agentic loop.
  26 | pub(crate) fn mark_budget_active() {
  27 |     BUDGET_ACTIVE.with(|c| c.set(true));
  28 | }
  29 | 
  30 | /// Clear the step-limit flag because the run completed within budget.
  31 | pub(crate) fn clear_budget() {
  32 |     BUDGET_ACTIVE.with(|c| c.set(false));
  33 | }
  34 | 
  35 | /// Returns `true` if the step budget was active (not cleared) after the
  36 | /// agentic loop exited, indicating the run hit the `max_steps` ceiling.
  37 | pub fn was_budget_exhausted() -> bool {
  38 |     BUDGET_ACTIVE.with(|c| c.get())
  39 | }

