   1 | //! Connection lifecycle state machine for the worker stream (Phase 5).
   2 | //!
   3 | //! Models the reconnect lifecycle explicitly instead of leaving it implicit in a
   4 | //! `loop { connect; sleep }`. The state is driven by connect outcomes and the
   5 | //! circuit breaker. See `docs/transport-first-class-plan.md` Phase 5.
   6 | 
   7 | /// Observable connection lifecycle state.
   8 | ///
   9 | /// # Examples
  10 | ///
  11 | /// ```rust
  12 | /// use codetether_agent::a2a::stream::lifecycle::{LifecycleState, next_state};
  13 | ///
  14 | /// // A successful connect moves Connecting -> Live.
  15 | /// assert_eq!(next_state(LifecycleState::Connecting, true, false), LifecycleState::Live);
  16 | /// // A failure with the breaker still closed -> Backoff.
  17 | /// assert_eq!(next_state(LifecycleState::Live, false, false), LifecycleState::Backoff);
  18 | /// // A failure with the breaker open -> Dead.
  19 | /// assert_eq!(next_state(LifecycleState::Live, false, true), LifecycleState::Dead);
  20 | /// ```
  21 | #[derive(Debug, Clone, Copy, PartialEq, Eq)]
  22 | pub enum LifecycleState {
  23 |     /// Attempting to establish the stream.
  24 |     Connecting,
  25 |     /// Stream established and delivering events.
  26 |     Live,
  27 |     /// Stream dropped; will reconnect after backoff.
  28 |     Backoff,
  29 |     /// Breaker tripped; server appears hard-down.
  30 |     Dead,
  31 | }
  32 | 
  33 | /// Compute the next lifecycle state from the current state and the last
  34 | /// connect outcome.
  35 | ///
  36 | /// `connected` is whether the most recent connect attempt succeeded;
  37 | /// `breaker_open` is whether the circuit breaker has tripped.
  38 | pub fn next_state(_current: LifecycleState, connected: bool, breaker_open: bool) -> LifecycleState {
