   1 | //! Durable client-side resume cursor: the last *fully processed* event id.
   2 | //!
   3 | //! The cursor advances only after a sequenced event's side effects commit, never
   4 | //! on mere receipt. See `docs/transport-phase1-wire-contract.md` section 6.
   5 | 
   6 | use std::fs;
   7 | use std::path::PathBuf;
   8 | 
   9 | use super::event_id::EventId;
  10 | 
  11 | /// A file-backed cursor recording the last successfully processed [`EventId`].
  12 | ///
  13 | /// # Examples
  14 | ///
  15 | /// ```rust
  16 | /// # let dir = tempfile::tempdir().unwrap();
  17 | /// # let path = dir.path().join("cursor");
  18 | /// use codetether_agent::a2a::stream::cursor::Cursor;
  19 | /// use codetether_agent::a2a::stream::event_id::EventId;
  20 | ///
  21 | /// let mut cursor = Cursor::load(path.clone());
  22 | /// assert!(cursor.last().is_none());
  23 | ///
  24 | /// cursor.commit(&EventId { epoch: "e".into(), seq: 7 }).unwrap();
  25 | /// let reloaded = Cursor::load(path);
  26 | /// assert_eq!(reloaded.last().unwrap().seq, 7);
  27 | /// ```
  28 | pub struct Cursor {
  29 |     path: PathBuf,
  30 |     last: Option<EventId>,
  31 | }
  32 | 
  33 | impl Cursor {
  34 |     /// Load a cursor from `path`, returning an empty cursor when absent/invalid.
  35 |     pub fn load(path: PathBuf) -> Self {
  36 |         let last = fs::read_to_string(&path)
  37 |             .ok()
  38 |             .and_then(|s| EventId::parse(s.trim()));
  39 |         Self { path, last }
  40 |     }
  41 | 
  42 |     /// The last processed event id, if any.
  43 |     pub fn last(&self) -> Option<&EventId> {
  44 |         self.last.as_ref()
  45 |     }
  46 | 
  47 |     /// Persist `id` as the new commit point (write-through to disk).
  48 |     ///
  49 |     /// # Errors
  50 |     ///
  51 |     /// Returns an error if the cursor file cannot be written.
  52 |     pub fn commit(&mut self, id: &EventId) -> std::io::Result<()> {
  53 |         fs::write(&self.path, id.format())?;
  54 |         self.last = Some(id.clone());
  55 |         Ok(())
  56 |     }
  57 | 
  58 |     /// Drop the cursor (in memory and on disk) for a cold resync.
  59 |     ///
  60 |     /// A missing file is treated as already-reset and is not an error.
  61 |     ///
  62 |     /// # Errors
  63 |     ///
  64 |     /// Returns an error if the cursor file exists but cannot be removed.
  65 |     pub fn reset(&mut self) -> std::io::Result<()> {
  66 |         self.last = None;
  67 |         match fs::remove_file(&self.path) {
  68 |             Ok(()) => Ok(()),
  69 |             Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(()),
  70 |             Err(e) => Err(e),
  71 |         }
  72 |     }
  73 | }

