  14 |     let title = task_str(task, "title").unwrap_or("Untitled");
  15 |     let mut timeline = task_timeline::TaskTimeline::new(task_id, timeout_secs(task));
  16 |     timeline.checkpoint(task_timeline::TaskCheckpoint::TaskReceived);
  17 |     tracing::info!(task_id, title, "Handling task");
  18 |     sync_timeline_to_runtime(&timeline, runtime).await;
  19 | 
