  29 |         claimed.provider_keys,
  30 |         &mut timeline,
  31 |     )
  32 |     .await;
  33 |     let outcome = task_outcome::from_inner(task_id, inner, &mut timeline);
  34 |     task_handler_release::release_handled_task(runtime, task_id, outcome, &mut timeline).await
  35 | }
