   5 | 
   6 | /// Delivery class of a stream event.
   7 | ///
   8 | /// # Examples
   9 | ///
  10 | /// ```rust
  11 | /// use codetether_agent::a2a::stream::classify::{classify, EventClass};
  12 | ///
  13 | /// assert_eq!(classify("task_available"), EventClass::Advisory);
  14 | /// assert_eq!(classify("heartbeat"), EventClass::Control);
  15 | /// assert_eq!(classify("result"), EventClass::Sequenced);
  16 | /// ```
  17 | #[derive(Debug, Clone, Copy, PartialEq, Eq)]
  18 | pub enum EventClass {
  19 |     /// Claim-gated, at-least-once, never sequenced (e.g. `task_available`).
  20 |     Advisory,
  21 |     /// Liveness/handshake, never sequenced (e.g. `heartbeat`, `connected`).
  22 |     Control,
  23 |     /// Exactly-once in-order state events; carry an `id:` and move the cursor.
  24 |     Sequenced,
  25 | }
  26 | 
  27 | /// Classify an event type string into its [`EventClass`].
  28 | ///
  29 | /// Unknown types default to [`EventClass::Sequenced`] so new state events are
  30 | /// resumed conservatively rather than silently dropped from the cursor.
  31 | pub fn classify(event_type: &str) -> EventClass {
  32 |     match event_type {
  33 |         "task_available" => EventClass::Advisory,
  34 |         "heartbeat" | "connected" | "resync-required" => EventClass::Control,
  35 |         _ => EventClass::Sequenced,
  36 |     }
  37 | }
