  19 | /// assert_eq!(frame.data, "{\"x\":1}");
  20 | /// ```
  21 | #[derive(Debug, Clone, PartialEq, Eq)]
  22 | pub struct ParsedFrame {
  23 |     /// Resumable event id when the server emitted an `id:` line.
  24 |     pub id: Option<EventId>,
  25 |     /// The `event:` type, defaulting to `message` when absent.
  26 |     pub event: String,
  27 |     /// The concatenated `data:` payload.
  28 |     pub data: String,
