  12 | use std::sync::Arc;
  13 | use std::time::Duration;
  14 | 
  15 | use anyhow::Result;
  16 | use tokio::sync::mpsc;
  17 | 
  18 | use crate::provider::{CompletionRequest, CompletionResponse, Provider};
  19 | use crate::session::SessionEvent;
  20 | 
  21 | use super::idle_timeout::drain;
  22 | 
  23 | /// Bounded restart budget with exponential backoff.
  24 | #[derive(Debug, Clone)]
  25 | pub(crate) struct RestartPolicy {
  26 |     pub(crate) max_restarts: u32,
  27 |     pub(crate) base_backoff: Duration,
  28 |     pub(crate) multiplier: u32,
  29 | }
  30 | 
  31 | impl Default for RestartPolicy {
  32 |     fn default() -> Self {
  33 |         Self {
  34 |             max_restarts: 3,
  35 |             base_backoff: Duration::from_secs(2),
  36 |             multiplier: 2,
  37 |         }
  38 |     }
  39 | }
  40 | 
  41 | impl RestartPolicy {
  42 |     /// Backoff before the `attempt`-th restart (0-based): base * mult^attempt.
  43 |     pub(crate) fn backoff(&self, attempt: u32) -> Duration {
  44 |         self.base_backoff * self.multiplier.saturating_pow(attempt)
  45 |     }
  46 | }
  47 | 
  48 | /// Drive a streamed completion with SRP restarts.
  49 | ///
  50 | /// Opens a stream, drains it, and on a restart-eligible stop re-opens a fresh
  51 | /// stream (after backoff) until [`RestartPolicy::max_restarts`] is exhausted.
  52 | /// Returns the assembled response, or the last error when the budget runs out.
  53 | pub(crate) async fn run(
  54 |     provider: &Arc<dyn Provider>,
  55 |     request: CompletionRequest,
  56 |     event_tx: Option<&mpsc::Sender<SessionEvent>>,
  57 |     policy: &RestartPolicy,
  58 | ) -> Result<CompletionResponse> {
  59 |     let mut attempt = 0u32;
  60 |     loop {
  61 |         let stream = provider.complete_stream(request.clone()).await?;
  62 |         let outcome = drain(stream, event_tx).await;
  63 |         let restart = outcome.stop.restart_eligible()
  64 |             && (!outcome.committed() || outcome.stop.restart_over_committed())
  65 |             && attempt < policy.max_restarts;
  66 |         if !restart {
  67 |             return super::accept::accept(outcome, attempt);
  68 |         }
  69 |         let wait = policy.backoff(attempt);
  70 |         attempt += 1;
  71 |         tracing::warn!(attempt, stop = ?outcome.stop, wait_secs = wait.as_secs(), "SRP restart");
  72 |         tokio::time::sleep(wait).await;
  73 |     }
  74 | }

