   1 | //! Liveness keepalive for the provider inference wait.
   2 | //!
   3 | //! While the provider is "thinking" before its first chunk (slow models like
   4 | //! Bedrock Opus or GLM can take 60-90 s), no [`StreamChunk`] arrives and the
   5 | //! session emits no [`SessionEvent`]. The TUI watchdog only sees
   6 | //! `SessionEvent`s, so without a keepalive it would cancel a healthy request.
   7 | //!
   8 | //! [`next_with_keepalive`] polls the stream on a short tick and emits a
   9 | //! [`SessionEvent::Thinking`] keepalive between polls, so the *same* event
  10 | //! stream the TUI watchdog already consumes reflects in-flight liveness. The
  11 | //! caller's total idle budget ([`IDLE_TIMEOUT`]) is unchanged — keepalives only
  12 | //! refresh the UI's activity clock, they do not reset the cold-stall budget.
  13 | //!
  14 | //! [`IDLE_TIMEOUT`]: super::idle_timeout::IDLE_TIMEOUT
  15 | 
  16 | use std::time::Duration;
  17 | 
  18 | use crate::provider::StreamChunk;
  19 | use crate::session::SessionEvent;
  20 | use futures::StreamExt;
  21 | use futures::stream::BoxStream;
  22 | use tokio::time::Instant;
  23 | 
  24 | /// How often to emit a liveness keepalive while awaiting the next chunk.
  25 | const KEEPALIVE_TICK: Duration = Duration::from_secs(10);
  26 | 
  27 | /// Outcome of waiting for the next chunk with periodic keepalives.
  28 | pub(super) enum Next {
  29 |     /// A chunk arrived (or the stream ended with `None`).
  30 |     Chunk(Option<StreamChunk>),
  31 |     /// The total `budget` elapsed with no chunk.
  32 |     IdleTimeout,
  33 | }
  34 | 
  35 | /// Await the next chunk, emitting `Thinking` keepalives every [`KEEPALIVE_TICK`].
  36 | ///
  37 | /// Returns once a chunk arrives, the stream ends, or `budget` is exhausted.
  38 | pub(super) async fn next_with_keepalive(
  39 |     stream: &mut BoxStream<'static, StreamChunk>,
  40 |     event_tx: Option<&tokio::sync::mpsc::Sender<SessionEvent>>,
  41 |     budget: Duration,
  42 | ) -> Next {
  43 |     // `tokio::time::Instant` shares tokio's clock with `timeout` below, so the
  44 |     // budget depletes in lockstep with the timers (and advances under paused
  45 |     // virtual time in tests). A `std::time::Instant` here would never expire
  46 |     // under `start_paused` and would drift from the timer clock in production.
  47 |     let start = Instant::now();
  48 |     loop {
  49 |         let remaining = budget.saturating_sub(start.elapsed());
  50 |         if remaining.is_zero() {
  51 |             return Next::IdleTimeout;
  52 |         }
  53 |         let tick = KEEPALIVE_TICK.min(remaining);
  54 |         match tokio::time::timeout(tick, stream.next()).await {
  55 |             Ok(chunk) => return Next::Chunk(chunk),
  56 |             Err(_) => {
  57 |                 if let Some(tx) = event_tx {
  58 |                     let _ = tx.send(SessionEvent::Thinking).await;
  59 |                 }
  60 |             }
  61 |         }
  62 |     }
  63 | }
  64 | 
  65 | #[cfg(test)]
  66 | #[path = "idle_keepalive_tests.rs"]
  67 | mod tests;

